from flask import request, jsonify

def validate_and_deserialize_registration_data():
    data = request.get_json()

    if not isinstance(data, dict):
        return jsonify({"error": "Invalid data format"}), 400

    name = data.get("name")
    email = data.get("email")
    password = data.get("password")

    if not isinstance(name, str) or not name:
        return jsonify({"error": "Name is required and must be a string"}), 400

    if not isinstance(email, str) or not email:
        return jsonify({"error": "Email is required and must be a string"}), 400

    if not isinstance(password, str) or not password:
        return jsonify({"error": "Password is required and must be a string"}), 400

    return {"name": name, "email": email, "password": password}

import pytest

def celsius_to_fahrenheit(celsius):
    return (celsius * 9/5) + 32

def fahrenheit_to_celsius(fahrenheit):
    return (fahrenheit - 32) * 5/9

@pytest.mark.parametrize("celsius, expected_fahrenheit", [
    (0, 32),        # Freezing point
    (100, 212),    # Boiling point
    (37, 98.6),    # Body temperature
    (-40, -40),    # Equal point
    (20, 68)       # Room temperature
])
def test_celsius_to_fahrenheit(celsius, expected_fahrenheit):
    assert celsius_to_fahrenheit(celsius) == expected_fahrenheit

@pytest.mark.parametrize("fahrenheit, expected_celsius", [
    (32, 0),        # Freezing point
    (212, 100),    # Boiling point
    (98.6, 37),    # Body temperature
    (-40, -40),    # Equal point
    (68, 20)       # Room temperature
])
def test_fahrenheit_to_celsius(fahrenheit, expected_celsius):
    assert fahrenheit_to_celsius(fahrenheit) == expected_celsius

